const input = $json;
const previousFeedback = input.previous_feedback || '';
const isRetry = previousFeedback.trim().length > 0;
const sessionId = input.session_id || ((input.project_id || 'proj') + '-' + (input.task?.task_id || 'default'));
if (isRetry) {
  // P2/P3: agent already has the code in conversation history — just send the feedback
  return [{ json: {
    session_id: sessionId,
    task: input.task,
    project_goal: input.project_goal,
    user_message: `Issues found in your code. Fix ALL of them:\n\n${previousFeedback}\n\nOutput only the files that need to change, using the same ### path/to/file.ext \`\`\`lang ... \`\`\` format as before.`
  } }];
}
// P1: full context message
let taskDescription = input.task?.description || input.description || '';
if (!taskDescription && input.task?.raw_output) {
  const raw = input.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) { taskDescription = raw; }
}
const existingFiles = input.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nEXISTING PROJECT FILES (read carefully — modify or extend, do NOT rewrite files that do not need changes):\n' +
    existingFiles.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n')
  : '';
return [{ json: {
  session_id: sessionId,
  task: input.task,
  project_goal: input.project_goal,
  user_message: `Task:\n${taskDescription}${existingFilesSection}`
} }];

const raw = $json.output || '';
// Strip thinking tokens if model emits them
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|Dockerfile|gitignore))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path) && fileContent.trim().length > 20) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { files, task: trigger.task, project_goal: trigger.project_goal } }];
